function getIconSuggestions(partial, limit = 10) {
  const lowerPartial = partial.toLowerCase();
  const exactMatches = AllIconNames.filter(
    (name) => name.toLowerCase() === lowerPartial
  );
  const startsWithMatches = AllIconNames.filter(
    (name) => name.toLowerCase().startsWith(lowerPartial) && !exactMatches.includes(name)
  );
  const containsMatches = AllIconNames.filter(
    (name) => name.toLowerCase().includes(lowerPartial) && !exactMatches.includes(name) && !startsWithMatches.includes(name)
  );
  return [
    ...exactMatches,
    ...startsWithMatches,
    ...containsMatches
  ].slice(0, limit);
}
function searchIcons(query) {
  if (!query.trim()) return [];
  const keywords = query.toLowerCase().split(/\s+/);
  return AllIconNames.filter((name) => {
    const nameLower = name.toLowerCase();
    return keywords.every((keyword) => nameLower.includes(keyword));
  });
}

